from collections import deque, defaultdict
import sys

def solve(nums: list[int]) -> int:
    n = len(nums)
    if n == 0:
        return 0

    max_spf = 10**6
    spf = list(range(max_spf + 1))  # Initialize spf[i] = i

    for i in range(2, int(max_spf**0.5) + 1):
        if spf[i] == i:  # i is prime
            for j in range(i * i, max_spf + 1, i):
                if spf[j] == j:
                    spf[j] = i

    prime_to_indices = defaultdict(list)
    is_prime = [False] * n

    for j in range(n):
        x = nums[j]
        if x == 1:
            is_prime[j] = False
            continue

        factors = set()
        temp = x
        while temp != 1:
            p = spf[temp]
            factors.add(p)
            while temp % p == 0:
                temp //= p

        for p in factors:
            prime_to_indices[p].append(j)

        if spf[x] == x:
            is_prime[j] = True
        else:
            is_prime[j] = False

    dist = [-1] * n
    q = deque()
    dist[0] = 0
    q.append(0)

    while q:
        i = q.popleft()
        if i == n - 1:
            return dist[i]

        for next_i in [i - 1, i + 1]:
            if 0 <= next_i < n and dist[next_i] == -1:
                dist[next_i] = dist[i] + 1
                q.append(next_i)

        if is_prime[i]:
            p = nums[i]
            for j in prime_to_indices[p]:
                if j != i and dist[j] == -1:
                    dist[j] = dist[i] + 1
                    q.append(j)

    return dist[n - 1]
